### Type Preservation with Field Guards

Source: https://github.com/payloadcms/payload/blob/main/tools/claude-plugin/skills/payload/reference/FIELD-TYPE-GUARDS.md

Demonstrates how field guards preserve original type constraints when applied to both Field and ClientField types. Guards narrow field types accurately, maintaining type safety across server and client contexts while providing proper TypeScript type inference.

```typescript
import type { ClientField, Field } from 'payload'
import { fieldHasSubFields } from 'payload'

function processServerField(field: Field) {
  if (fieldHasSubFields(field)) {
    // field is Field & FieldWithSubFields (not ClientField)
  }
}

function processClientField(field: ClientField) {
  if (fieldHasSubFields(field)) {
    // field is ClientField & FieldWithSubFieldsClient
  }
}
```

